"use client";
import React, { useState, useEffect } from "react";

const TECH_ICONS: { name: string; icon: string }[] = [
  { name: "Python", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/python/python-original.svg" },
  { name: "JavaScript", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/javascript/javascript-original.svg" },
  { name: "TypeScript", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/typescript/typescript-original.svg" },
  { name: "React", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/react/react-original.svg" },
  { name: "Node.js", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/nodejs/nodejs-original.svg" },
  { name: "Flask", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/flask/flask-original.svg" },
  { name: "TensorFlow", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/tensorflow/tensorflow-original.svg" },
  { name: "Git", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/git/git-original.svg" },
  { name: "Linux", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/linux/linux-original.svg" },
  { name: "Docker", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/docker/docker-original.svg" },
  { name: "PostgreSQL", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/postgresql/postgresql-original.svg" },
  { name: "Figma", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/figma/figma-original.svg" },
  { name: "HTML5", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/html5/html5-original.svg" },
  { name: "CSS3", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/css3/css3-original.svg" },
  { name: "VS Code", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/vscode/vscode-original.svg" },
  { name: "MongoDB", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/mongodb/mongodb-original.svg" },
  { name: "Next.js", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/nextjs/nextjs-original.svg" },
  { name: "Bash", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/bash/bash-original.svg" },
  { name: "OpenCV", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/opencv/opencv-original.svg" },
  { name: "Chrome", icon: "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/chrome/chrome-original.svg" },
];

function SemiCircleOrbit({
  radius,
  centerX,
  centerY,
  count,
  iconSize,
  startIndex,
}: {
  radius: number;
  centerX: number;
  centerY: number;
  count: number;
  iconSize: number;
  startIndex: number;
}) {
  return (
    <>
      {Array.from({ length: count }).map((_, index) => {
        const angle = (index / (count - 1)) * 180;
        const x = radius * Math.cos((angle * Math.PI) / 180);
        const y = radius * Math.sin((angle * Math.PI) / 180);
        const tech = TECH_ICONS[(startIndex + index) % TECH_ICONS.length];

        const tooltipAbove = angle > 90;

        return (
          <div
            key={index}
            className="absolute flex flex-col items-center group"
            style={{
              left: `${centerX + x - iconSize / 2}px`,
              top: `${centerY - y - iconSize / 2}px`,
              zIndex: 5,
            }}
          >
            <img
              src={tech.icon}
              alt={tech.name}
              width={iconSize}
              height={iconSize}
              className="object-contain cursor-pointer transition-transform hover:scale-125 drop-shadow-lg"
              style={{ minWidth: iconSize, minHeight: iconSize, filter: "drop-shadow(0 0 8px rgba(0,200,255,0.3))" }}
            />

            <div
              className={`absolute ${tooltipAbove
                  ? "bottom-[calc(100%+8px)]"
                  : "top-[calc(100%+8px)]"
                } hidden group-hover:block w-28 rounded-lg bg-black/90 backdrop-blur-sm px-2 py-1 text-xs text-cyan-300 shadow-lg text-center border border-cyan-500/20`}
            >
              {tech.name}
              <div
                className={`absolute left-1/2 -translate-x-1/2 w-3 h-3 rotate-45 bg-black/90 ${tooltipAbove ? "top-full" : "bottom-full"
                  }`}
              ></div>
            </div>
          </div>
        );
      })}
    </>
  );
}

export default function MultiOrbitSemiCircle() {
  const [size, setSize] = useState({ width: 0, height: 0 });

  useEffect(() => {
    const updateSize = () =>
      setSize({ width: window.innerWidth, height: window.innerHeight });
    updateSize();
    window.addEventListener("resize", updateSize);
    return () => window.removeEventListener("resize", updateSize);
  }, []);

  const baseWidth = Math.min(size.width * 0.8, 700);
  const centerX = baseWidth / 2;
  const centerY = baseWidth * 0.5;

  const iconSize =
    size.width < 480
      ? Math.max(24, baseWidth * 0.05)
      : size.width < 768
        ? Math.max(28, baseWidth * 0.06)
        : Math.max(32, baseWidth * 0.07);

  return (
    <section className="py-12 relative min-h-screen w-full overflow-hidden">
      {/* Semi-circle glow background */}
      <div className="absolute inset-0 flex justify-center pointer-events-none">
        <div
          className="w-[1000px] h-[1000px] rounded-full bg-[radial-gradient(circle_at_center,rgba(0,200,255,0.08),transparent_70%)] blur-3xl mt-20"
        />
      </div>

      <div className="relative flex flex-col items-center text-center z-10">
        <h2 className="my-6 text-4xl font-bold lg:text-7xl text-white">
          Technology Stack
        </h2>
        <p className="mb-12 max-w-2xl text-gray-400 lg:text-xl">
          The tools and technologies I use to build secure, intelligent, and
          beautiful applications.
        </p>

        <div
          className="relative"
          style={{ width: baseWidth, height: baseWidth * 0.6 }}
        >
          <SemiCircleOrbit
            radius={baseWidth * 0.22}
            centerX={centerX}
            centerY={centerY}
            count={5}
            iconSize={iconSize}
            startIndex={0}
          />
          <SemiCircleOrbit
            radius={baseWidth * 0.36}
            centerX={centerX}
            centerY={centerY}
            count={7}
            iconSize={iconSize}
            startIndex={5}
          />
          <SemiCircleOrbit
            radius={baseWidth * 0.5}
            centerX={centerX}
            centerY={centerY}
            count={8}
            iconSize={iconSize}
            startIndex={12}
          />
        </div>
      </div>
    </section>
  );
}
